  4→export interface IconProps {
  5→  size?: number;
  6→  color?: string;
  7→  filled?: boolean;
  8→  strokeWidth?: number;
  9→}
 10→
 11→const defaults = {size: 24, color: '#888', strokeWidth: 1.8};
 12→
 13→function I({
 14→  size = defaults.size,
 15→  color = defaults.color,
 16→  children,
 17→}: IconProps & {children: React.ReactNode}) {
 18→  return (
 19→    <Svg
 20→      width={size}
 21→      height={size}
 22→      viewBox="0 0 24 24"
 23→      fill="none"
 24→      stroke={color}
 25→      strokeWidth={defaults.strokeWidth}
 26→      strokeLinecap="round"
 27→      strokeLinejoin="round">
 28→      {children}
 29→    </Svg>
 30→  );
 31→}
