 33→export function HeartIcon({size, color, filled, strokeWidth}: IconProps) {
 34→  const sw = strokeWidth ?? defaults.strokeWidth;
 35→  return (
 36→    <Svg
 37→      width={size ?? defaults.size}
 38→      height={size ?? defaults.size}
 39→      viewBox="0 0 24 24"
 40→      fill={filled ? color ?? defaults.color : 'none'}
 41→      stroke={color ?? defaults.color}
 42→      strokeWidth={sw}
 43→      strokeLinecap="round"
 44→      strokeLinejoin="round">
 45→      <Path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z" />
 46→    </Svg>
