 26→import {useComments} from '../../hooks/useComments';
 27→import {fonts, typeScale} from '../../theme/typography';
 28→import {spacing, radii} from '../../theme/spacing';
 29→import {mobileApi} from '../../lib/api/mobileApi';
 30→import {socialApi} from '../../lib/api/socialApi';
 31→import {queryClient} from '../../lib/queryClient';
 32→import {extractPlainText} from '../../lib/utils/journalHelpers';
 33→import type {RootStackParamList} from '../../navigation/types';
 34→
 35→type Props = NativeStackScreenProps<RootStackParamList, 'PostDetail'>;
 36→
 37→const toCount = (value: unknown): number | null => {
 38→  const parsed = Number(value);
 39→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : null;
 40→};
 41→
 42→const resolveCount = (
 43→  aggregate: Array<{count?: number}> | undefined,
 44→  fallback?: number,
 45→): number => {
 46→  return toCount(aggregate?.[0]?.count) ?? toCount(fallback) ?? 0;
 47→};
 48→
 49→const extractBannerImage = (content: string | null | undefined): string | null => {
 50→  if (!content) return null;
 51→  try {
 52→    const parsed = JSON.parse(content);
 53→    const findImage = (node: any): string | null => {
 54→      if (node.type === 'image' && node.src) return node.src;
 55→      if (node.children) {
 56→        for (const child of node.children) {
 57→          const found = findImage(child);
 58→          if (found) return found;
 59→        }
 60→      }
 61→      return null;
 62→    };
 63→    return findImage(parsed.root ?? parsed);
 64→  } catch {
 65→    return null;
 66→  }
 67→};
 68→
 69→export function PostDetailScreen({route, navigation}: Props) {
 70→  const {user, session} = useAuth();
 71→  const {colors} = useTheme();
 72→  const {journalId} = route.params;
 73→  const token = session?.access_token ?? '';
 74→  const [repostCaption, setRepostCaption] = useState('');
 75→  const [showRepost, setShowRepost] = useState(false);
 76→  const scrollViewRef = useRef<ScrollView>(null);
 77→  const inputRef = useRef<TextInput>(null);
 78→
 79→  const onReplyActivated = useCallback(() => {
 80→    setTimeout(() => {
 81→      inputRef.current?.focus();
 82→      scrollViewRef.current?.scrollToEnd({animated: true});
 83→    }, 100);
 84→  }, []);
 85→
 86→  const detailQuery = useQuery({
 87→    queryKey: ['journal', journalId, user?.id],
 88→    queryFn: () => mobileApi.getJournalById(journalId, user?.id),
 89→  });
 90→
 91→  const receiverId = (detailQuery.data?.journal?.user_id ?? detailQuery.data?.journal?.users?.id) || undefined;
 92→
 93→  const {
 94→    comments,
 95→    isLoading: commentsLoading,
 96→    commentInput,
 97→    setCommentInput,
 98→    replyingTo,
 99→    setReplyingTo,
100→    expandedReplies,
101→    fetchedReplies,
102→    loadingReplies,
103→    handleReply,
104→    handleToggleReplies,
105→    submitComment,
106→    isSubmitting,
107→  } = useComments(journalId, receiverId, token, onReplyActivated);
108→
109→  const reactionMutation = useMutation({
110→    mutationFn: async (reactionType: string) => {
111→      const journal = detailQuery.data?.journal;
112→      const rid = journal?.user_id ?? journal?.users?.id;
113→      if (!token) throw new Error('Please log in to react.');
114→      if (!journal?.id || !rid) throw new Error('Missing journal data.');
115→      return socialApi.toggleReaction(token, {
116→        journalId: journal.id,
117→        receiverId: rid,
118→        reactionType,
119→      });
120→    },
121→    onSuccess: () => {
122→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
123→      queryClient.invalidateQueries({queryKey: ['feed']});
124→    },
125→    onError: e => Alert.alert('Reaction failed', e instanceof Error ? e.message : 'Error'),
126→  });
127→
128→  const bookmarkMutation = useMutation({
129→    mutationFn: async () => {
130→      if (!token) throw new Error('Please log in to bookmark.');
131→      return socialApi.toggleBookmark(token, {journalId});
132→    },
133→    onSuccess: () => {
134→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
135→      queryClient.invalidateQueries({queryKey: ['feed']});
136→    },
137→    onError: e => Alert.alert('Bookmark failed', e instanceof Error ? e.message : 'Error'),
138→  });
139→
140→  const repostMutation = useMutation({
141→    mutationFn: async () => {
142→      if (!token) throw new Error('Please log in to repost.');
143→      return socialApi.createRepost(token, {
144→        sourceJournalId: journalId,
145→        caption: repostCaption.trim() || undefined,
146→      });
147→    },
148→    onSuccess: () => {
149→      setRepostCaption('');
150→      setShowRepost(false);
151→      Alert.alert('Reposted', 'Post was reposted to your feed.');
152→      queryClient.invalidateQueries({queryKey: ['feed']});
153→    },
154→    onError: e => Alert.alert('Repost failed', e instanceof Error ? e.message : 'Error'),
155→  });
156→
157→  const journal = detailQuery.data?.journal;
158→  const likeCount = resolveCount(journal?.like_count, journal?.likes_count);
159→  const commentCount = resolveCount(journal?.comment_count, journal?.comments_count);
160→  const bookmarkCount = resolveCount(journal?.bookmark_count);
161→  const bannerImage = useMemo(() => extractBannerImage(journal?.content), [journal?.content]);
162→  const isRepost = !!journal?.is_repost;
163→  const repostSource = isRepost ? journal?.repost_source : null;
164→  const repostSourcePreview = repostSource?.content
165→    ? extractPlainText(repostSource.content).slice(0, 200)
166→    : '';
167→
168→  if (detailQuery.isLoading) {
169→    return (
170→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
171→        <View style={styles.loadingContainer}>
172→          <SkeletonLoader height={200} borderRadius={0} />
173→          <View style={styles.contentPadding}>
174→            <SkeletonLoader width="70%" height={24} />
175→            <SkeletonLoader width="40%" height={16} style={{marginTop: 12}} />
176→            <SkeletonLoader width="100%" height={16} style={{marginTop: 20}} />
177→            <SkeletonLoader width="100%" height={16} style={{marginTop: 8}} />
178→            <SkeletonLoader width="60%" height={16} style={{marginTop: 8}} />
179→          </View>
180→        </View>
181→      </SafeAreaView>
182→    );
183→  }
184→
185→  if (detailQuery.isError) {
186→    return (
187→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
188→        <View style={styles.contentPadding}>
189→          <Text style={[styles.errorText, {color: colors.danger}]}>
190→            Unable to load this post.
191→          </Text>
192→        </View>
193→      </SafeAreaView>
194→    );
195→  }
196→
197→  return (
198→    <ScrollView
199→      ref={scrollViewRef}
200→      style={[styles.scroll, {backgroundColor: colors.bgPrimary}]}
201→      showsVerticalScrollIndicator={false}>
202→      {/* Banner image */}
203→      {!isRepost && bannerImage && (
204→        <Image source={{uri: bannerImage}} style={styles.banner} resizeMode="cover" />
205→      )}
206→
207→      <View style={styles.contentPadding}>
208→        {/* Title / Repost badge */}
209→        {isRepost ? (
210→          <View style={styles.repostBadge}>
211→            <RepostIcon size={14} color={colors.textFaint} />
212→            <Text style={[styles.repostBadgeText, {color: colors.textFaint}]}>
213→              <Text style={[styles.repostBadgeName, {color: colors.textSecondary}]}>
