380→              />
381→            ))
382→        )}
383→
384→        {/* Comment input */}
385→        {token ? (
386→          <View style={styles.commentInputRow}>
387→            {replyingTo && (
388→              <View style={[styles.replyBanner, {backgroundColor: colors.bgSecondary}]}>
389→                <Text style={[styles.replyBannerText, {color: colors.textPrimary}]}>
390→                  Replying to {replyingTo.userName}
391→                </Text>
392→                <Pressable onPress={() => setReplyingTo(null)} hitSlop={8}>
393→                  <XIcon size={16} color={colors.textMuted} />
394→                </Pressable>
395→              </View>
396→            )}
397→            <TextInput
398→              ref={inputRef}
399→              value={commentInput}
400→              onChangeText={setCommentInput}
401→              placeholder={replyingTo ? `Reply to ${replyingTo.userName}...` : 'Write a comment...'}
402→              placeholderTextColor={colors.textFaint}
403→              style={[
404→                styles.commentInput,
405→                {
406→                  backgroundColor: colors.bgSecondary,
407→                  borderColor: colors.borderCard,
408→                  color: colors.textPrimary,
409→                },
410→              ]}
411→              maxLength={200}
412→              multiline
413→            />
414→            <PrimaryButton
415→              label={isSubmitting ? 'Posting...' : 'Post'}
416→              onPress={submitComment}
417→              disabled={commentInput.trim().length === 0 || isSubmitting}
418→            />
419→          </View>
420→        ) : null}
421→
422→        <View style={styles.bottomSpacer} />
423→      </View>
424→    </ScrollView>
425→  );
426→}
