355→  safe: {
356→    flex: 1,
357→  },
358→  header: {
359→    paddingHorizontal: spacing.lg,
360→    paddingVertical: spacing.md,
361→    borderBottomWidth: StyleSheet.hairlineWidth,
362→  },
363→  brandText: {
364→    fontFamily: fonts.brand.semiBold,
365→    fontSize: 24,
366→    letterSpacing: 1,
367→  },
368→  chipRow: {
369→    paddingVertical: spacing.sm,
370→  },
371→  chipScroll: {
372→    paddingHorizontal: spacing.lg,
373→    gap: spacing.sm,
374→  },
375→  listContent: {
376→    paddingHorizontal: spacing.lg,
377→    paddingBottom: 100,
378→  },
379→  separator: {
380→    height: spacing.md,
381→  },
