163→function LoggedInShell({children}: {children: React.ReactNode}) {
164→  const {session} = useAuth();
165→  const userId = session?.user.id;
166→  const [toast, setToast] = useState<{message: string; visible: boolean}>({
167→    message: '',
168→    visible: false,
169→  });
170→
171→  const handleNewNotification = useCallback((payload: Record<string, unknown>) => {
172→    const message =
173→      (payload.message as string) || 'You have a new notification';
174→    setToast({message, visible: true});
175→  }, []);
176→
177→  const handleDismissToast = useCallback(() => {
178→    setToast(prev => ({...prev, visible: false}));
179→  }, []);
180→
181→  useRealtimeNotifications(userId, {
182→    onNewNotification: handleNewNotification,
183→  });
184→
185→  return (
186→    <View style={styles.shellContainer}>
187→      {children}
188→      <Toast
189→        message={toast.message}
190→        visible={toast.visible}
191→        onDismiss={handleDismissToast}
192→        type="info"
193→      />
194→    </View>
195→  );
196→}
